1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  KeyboardAvoidingView,
5	  Modal,
6	  Platform,
7	  Pressable,
8	  SafeAreaView,
9	  ScrollView,
10	  StyleSheet,
11	  Text,
12	  TextInput,
13	  type TextInputProps,
14	  View,
15	} from 'react-native';
16	import { router, useLocalSearchParams } from 'expo-router';
17	import { ChevronLeft } from 'lucide-react-native';
18	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
19	import { Chip } from '@/components/primitives/Chip';
20	import { useToast } from '@/components/primitives/Toast';
21	import { colors, radii, shadows, spacing } from '@/design/tokens';
22	import { textStyles } from '@/design/typography';
23	import { supabase } from '@/lib/supabase';
24	import type { Database } from '@/types/supabase';
25	
26	// US-055 — Edit campaign screen with cascade-cancel confirmation modal.
27	//
28	// Flow: fetch the listing (listings_owner_all RLS → owner only) → render
29	// editable fields → on Save, diff against the original. If any VERSIONED
30	// scalar field (price_cents, currency, max_submissions — per the
31	// us_010 cascade trigger at supabase/migrations/20260417150000) changed,
32	// count the listing's pending applications via PostgREST under the
33	// applications_lister_read policy, and if >0 show a confirm modal per
34	// docs/design.md §5.2 line 635 before issuing the PATCH. The DB trigger
35	// (app_private.bump_listing_version) performs the cascade + notification
36	// server-side on commit. Title/description/category edits DO NOT cascade
37	// (trigger guards on the versioned scalars only).
38	//
39	// Spec gap: pre/post conditions and sample_videos editing is deferred.
40	// Those require app_private.request_listing_version_bump to fire the cue
41	// column, and §15b threshold-refresh triggers (Codebase Pattern #52)
42	// MUST land first — both are out of scope for this story's AC which
43	// verifies the flow by editing a scalar (price).
44	
45	type Currency = 'USD' | 'EUR' | 'GBP';
46	type ListingRow = Database['public']['Tables']['listings']['Row'];
47	type ListingStatus = Database['public']['Enums']['listing_status'];
48	
49	const CURRENCIES: readonly Currency[] = ['USD', 'EUR', 'GBP'];
50	const CURRENCY_SYMBOL: Record<Currency, string> = { USD: '$', EUR: '€', GBP: '£' };
51	
52	// Price in major units with up to two decimals.
53	const PRICE_INPUT_RE = /^(\d+)?(\.\d{0,2})?$/;
54	// integer column in Postgres → cap at 2^31-1 (Codebase Pattern #131).
55	const PRICE_CENTS_MAX = 2_147_483_647;
56	const MAX_SUBMISSIONS_MAX = 99_999;
57	const MAX_SUBMISSIONS_INPUT_RE = /^\d*$/;
58	
59	function centsToDisplay(cents: number | null | undefined): string {
60	  if (cents == null) return '';
61	  if (cents % 100 === 0) return String(cents / 100);
62	  return (cents / 100).toFixed(2);
63	}
64	
65	function displayToCents(display: string): number | null {
66	  const trimmed = display.trim();
67	  if (!trimmed) return null;
68	  const n = Number.parseFloat(trimmed);
69	  if (!Number.isFinite(n) || n < 0) return null;
70	  return Math.round(n * 100);
71	}
72	
73	function isKnownCurrency(c: string): c is Currency {
74	  return (CURRENCIES as readonly string[]).includes(c);
75	}
76	
77	type LoadState =
78	  | { kind: 'loading' }
79	  | { kind: 'error'; code: 'not_found' | 'generic' }
80	  | { kind: 'loaded'; listing: ListingRow };
81	
82	export default function EditCampaignScreen() {
83	  const params = useLocalSearchParams<{ id: string }>();
84	  const listingId = typeof params.id === 'string' ? params.id : null;
85	  const toast = useToast();
86	
87	  const [state, setState] = useState<LoadState>({ kind: 'loading' });
88	
89	  // Form state. Initialized from the loaded row; "priceDisplay" is the
90	  // TextInput mirror so partial values like "12." survive keystrokes.
91	  const [title, setTitle] = useState('');
92	  const [description, setDescription] = useState('');
93	  const [priceDisplay, setPriceDisplay] = useState('');
94	  const [currency, setCurrency] = useState<Currency>('USD');
95	  const [maxSubmissionsDisplay, setMaxSubmissionsDisplay] = useState('');
96	
97	  // Modal state: null = closed, number = pending count to cascade-cancel.
98	  const [confirmCount, setConfirmCount] = useState<number | null>(null);
99	  const [saving, setSaving] = useState(false);
100	
101	  useEffect(() => {
102	    if (!listingId) {
103	      setState({ kind: 'error', code: 'not_found' });
104	      return;
105	    }
106	    let cancelled = false;
107	    (async () => {
108	      const { data, error } = await supabase
109	        .from('listings')
110	        .select('*')
111	        .eq('id', listingId)
112	        .maybeSingle();
113	      if (cancelled) return;
114	      if (error) {
115	        setState({ kind: 'error', code: 'generic' });
116	        return;
117	      }
118	      if (!data) {
119	        setState({ kind: 'error', code: 'not_found' });
120	        return;
121	      }
122	      setTitle(data.title);
123	      setDescription(data.description ?? '');
124	      setPriceDisplay(centsToDisplay(data.price_cents));
125	      setCurrency(isKnownCurrency(data.currency) ? data.currency : 'USD');
126	      setMaxSubmissionsDisplay(
127	        data.max_submissions == null ? '' : String(data.max_submissions),
128	      );
129	      setState({ kind: 'loaded', listing: data });
130	    })();
131	    return () => {
132	      cancelled = true;
133	    };
134	  }, [listingId]);
135	
136	  const parsedPriceCents = useMemo(() => displayToCents(priceDisplay), [priceDisplay]);
137	  const parsedMaxSubmissions = useMemo(() => {
138	    const t = maxSubmissionsDisplay.trim();
139	    if (!t) return null;
140	    const n = Number.parseInt(t, 10);
141	    if (!Number.isFinite(n) || n <= 0) return null;
142	    return n;
143	  }, [maxSubmissionsDisplay]);
144	
145	  const original = state.kind === 'loaded' ? state.listing : null;
146	
147	  // Changed-fields diff drives both the button enable state and the
148	  // versioned-field detection. We compare raw cents/ints (not display
149	  // strings) so "12" vs "12.00" doesn't count as a change.
150	  const diff = useMemo(() => {
151	    if (!original) {
152	      return { any: false, versioned: false, changed: [] as string[] };
153	    }
154	    const changed: string[] = [];
155	    if (title.trim() !== original.title) changed.push('title');
156	    if ((description.trim() || null) !== (original.description ?? null)) {
157	      changed.push('description');
158	    }
159	    if (parsedPriceCents !== original.price_cents) changed.push('price_cents');
160	    if (currency !== original.currency) changed.push('currency');
161	    if (parsedMaxSubmissions !== original.max_submissions) changed.push('max_submissions');
162	    const versioned =
163	      changed.includes('price_cents') ||
164	      changed.includes('currency') ||
165	      changed.includes('max_submissions');
166	    return { any: changed.length > 0, versioned, changed };
167	  }, [original, title, description, parsedPriceCents, currency, parsedMaxSubmissions]);
168	
169	  const inputsValid = useMemo(() => {
170	    if (title.trim().length === 0) return false;
171	    // price + max_submissions are nullable — empty strings are valid, but a
172	    // non-empty display that fails to parse is not.
173	    if (priceDisplay.trim() && parsedPriceCents === null) return false;
174	    if (parsedPriceCents !== null && parsedPriceCents > PRICE_CENTS_MAX) return false;
175	    if (maxSubmissionsDisplay.trim() && parsedMaxSubmissions === null) return false;
176	    if (parsedMaxSubmissions !== null && parsedMaxSubmissions > MAX_SUBMISSIONS_MAX) {
177	      return false;
178	    }
179	    return true;
180	  }, [title, priceDisplay, parsedPriceCents, maxSubmissionsDisplay, parsedMaxSubmissions]);
181	
182	  const canSave = state.kind === 'loaded' && diff.any && inputsValid && !saving;
183	
184	  const patchListing = useCallback(async () => {
185	    if (!listingId || !original) return;
186	    setSaving(true);
187	    const payload = {
188	      title: title.trim(),
189	      description: description.trim() || null,
190	      price_cents: parsedPriceCents ?? 0,
191	      currency,
192	      max_submissions: parsedMaxSubmissions,
193	    };
194	    const { error } = await supabase.from('listings').update(payload).eq('id', listingId);
195	    setSaving(false);
196	    if (error) {
197	      toast.show({ message: "Couldn't save changes.", variant: 'error' });
198	      return;
199	    }
200	    const msg = diff.versioned
201	      ? 'Changes saved. New version published.'
202	      : 'Changes saved.';
203	    toast.show({ message: msg, variant: 'success' });
204	    if (router.canGoBack()) router.back();
205	    else router.replace('/(lister)/campaigns');
206	  }, [
207	    listingId,
208	    original,
209	    title,
210	    description,
211	    parsedPriceCents,
212	    currency,
213	    parsedMaxSubmissions,
214	    diff.versioned,
215	    toast,
216	  ]);
217	
218	  const onSave = useCallback(async () => {
219	    if (!canSave || !listingId) return;
220	    // Non-versioned edits skip the cascade modal — no cascade server-side,
221	    // no creators to warn about.
222	    if (!diff.versioned) {
223	      void patchListing();
224	      return;
225	    }
226	    // Versioned edit → count pending applications BEFORE writing, so we
227	    // can show the exact cascade impact to the lister. If listing isn't
228	    // 'active' the trigger wouldn't cascade anyway, but we still query
229	    // under the same RLS policy — a non-active listing simply can't have
230	    // pending applications in this project (public_read gates on active).
231	    setSaving(true);
232	    const { count, error } = await supabase
233	      .from('applications')
234	      .select('id', { count: 'exact', head: true })
235	      .eq('listing_id', listingId)
236	      .eq('status', 'pending');
237	    setSaving(false);
238	    if (error) {
239	      toast.show({ message: "Couldn't check pending applications.", variant: 'error' });
240	      return;
241	    }
242	    const n = count ?? 0;
243	    if (n === 0) {
244	      // Nothing to cascade — commit directly with no interstitial.
245	      void patchListing();
246	      return;
247	    }
248	    setConfirmCount(n);
249	  }, [canSave, listingId, diff.versioned, patchListing, toast]);
250	
251	  const onConfirmCascade = useCallback(() => {
252	    setConfirmCount(null);
253	    void patchListing();
254	  }, [patchListing]);
255	
256	  const onDismissConfirm = useCallback(() => setConfirmCount(null), []);
257	
258	  const onBack = useCallback(() => {
259	    if (router.canGoBack()) router.back();
260	    else router.replace('/(lister)/campaigns');
261	  }, []);
262	
263	  if (state.kind === 'loading') {
264	    return (
265	      <SafeAreaView style={[styles.root, styles.center]}>
266	        <ActivityIndicator color={colors.ink} />
267	      </SafeAreaView>
268	    );
269	  }
270	
271	  if (state.kind === 'error') {
272	    return (
273	      <SafeAreaView style={[styles.root, styles.center]}>
274	        <Text style={[textStyles.body, { color: colors.danger, textAlign: 'center' }]}>
275	          {state.code === 'not_found' ? "Campaign not found." : "Couldn't load campaign."}
276	        </Text>
277	        <View style={{ height: spacing.lg }} />
278	        <ButtonSecondary label="Back" onPress={onBack} testID="edit-error-back" />
279	      </SafeAreaView>
280	    );
281	  }
282	
283	  return (
284	    <SafeAreaView style={styles.root}>
285	      <KeyboardAvoidingView
286	        style={styles.flex}
287	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
288	      >
289	        <ScrollView
290	          contentContainerStyle={styles.scroll}
291	          keyboardShouldPersistTaps="handled"
292	        >
293	          <View style={styles.header}>
294	            <Pressable
295	              onPress={onBack}
296	              hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
297	              accessibilityRole="button"
298	              accessibilityLabel="Back"
299	              testID="edit-back"
300	              style={styles.backBtn}
301	            >
302	              <ChevronLeft size={24} color={colors.ink} />
303	            </Pressable>
304	            <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
305	              {statusLabel(state.listing.status)}
306	            </Text>
307	            <Text style={[textStyles.display, styles.title]}>Edit campaign</Text>
308	            <Text
309	              style={[textStyles.body, styles.subtitle]}
310	              maxFontSizeMultiplier={1.3}
311	            >
312	              Changes to price, currency, or max submissions cancel pending applications.
313	            </Text>
314	          </View>
315	
316	          <View style={styles.fields}>
317	            <Field
318	              label="Title"
319	              value={title}
320	              onChange={setTitle}
321	              autoCapitalize="sentences"
322	              testID="edit-title"
323	            />
324	            <Field
325	              label="Description"
326	              value={description}
327	              onChange={setDescription}
328	              autoCapitalize="sentences"
329	              multiline
330	              testID="edit-description"
331	            />
332	            <Field
333	              label="Price"
334	              value={priceDisplay}
335	              onChange={(next) => {
336	                if (next !== '' && !PRICE_INPUT_RE.test(next)) return;
337	                setPriceDisplay(next);
338	              }}
339	              placeholder="0.00"
340	              keyboardType="decimal-pad"
341	              prefix={CURRENCY_SYMBOL[currency]}
342	              testID="edit-price"
343	            />
344	
345	            <View style={styles.field}>
346	              <Text style={[textStyles.caption, styles.label]}>Currency</Text>
347	              <View style={styles.chipRow}>
348	                {CURRENCIES.map((c) => (
349	                  <Chip
350	                    key={c}
351	                    label={c}
352	                    active={currency === c}
353	                    onPress={() => setCurrency(c)}
354	                    accessibilityLabel={`Currency ${c}`}
355	                    testID={`edit-currency-${c}`}
356	                  />
357	                ))}
358	              </View>
359	            </View>
360	
361	            <Field
362	              label="Max submissions (optional)"
363	              value={maxSubmissionsDisplay}
364	              onChange={(next) => {
365	                if (next !== '' && !MAX_SUBMISSIONS_INPUT_RE.test(next)) return;
366	                if (next.length > 5) return;
367	                setMaxSubmissionsDisplay(next);
368	              }}
369	              placeholder="Leave blank for unlimited"
370	              keyboardType="number-pad"
371	              testID="edit-max-submissions"
372	            />
373	          </View>
374	
375	          <ButtonPrimary
376	            label="Save changes"
377	            onPress={onSave}
378	            disabled={!canSave}
379	            loading={saving && confirmCount === null}
380	            accessibilityLabel="Save campaign changes"
381	            testID="edit-save"
382	          />
383	        </ScrollView>
384	      </KeyboardAvoidingView>
385	
386	      <CascadeConfirmModal
387	        count={confirmCount}
388	        saving={saving}
389	        onConfirm={onConfirmCascade}
390	        onDismiss={onDismissConfirm}
391	      />
392	    </SafeAreaView>
393	  );
394	}
395	
396	function statusLabel(s: ListingStatus): string {
397	  switch (s) {
398	    case 'active':
399	      return 'ACTIVE';
400	    case 'draft':
401	      return 'DRAFT';
402	    case 'paused':
403	      return 'PAUSED';
404	    case 'closed':
405	      return 'CLOSED';
406	    case 'archived':
407	      return 'ARCHIVED';
408	  }
409	}
410	
411	type CascadeConfirmModalProps = {
412	  count: number | null;
413	  saving: boolean;
414	  onConfirm: () => void;
415	  onDismiss: () => void;
416	};
417	
418	// Centered alert-style confirm. Design.md §3.3 carves out "modals (except
419	// confirmations) are bottom sheets" — confirmations are a centered card
420	// per §5.2 line 635. Keeps the same neubrutalist language (hard shadow,
421	// 2px ink border) as every other surface.
422	function CascadeConfirmModal({
423	  count,
424	  saving,
425	  onConfirm,
426	  onDismiss,
427	}: CascadeConfirmModalProps) {
428	  const visible = count !== null;
429	  return (
430	    <Modal
431	      visible={visible}
432	      transparent
433	      animationType="fade"
434	      statusBarTranslucent
435	      onRequestClose={onDismiss}
436	      testID="edit-cascade-modal"
437	    >
438	      <View style={styles.modalRoot}>
439	        <Pressable
440	          style={StyleSheet.absoluteFill}
441	          onPress={onDismiss}
442	          accessible={false}
443	          importantForAccessibility="no"
444	        />
445	        <View
446	          style={[styles.modalCard, shadows.hard]}
447	          accessibilityViewIsModal
448	          accessibilityLabel="Confirm cascade"
449	        >
450	          <Text style={[textStyles.h2, styles.modalTitle]} maxFontSizeMultiplier={1.3}>
451	            Cancel pending applications?
452	          </Text>
453	          <Text style={[textStyles.body, styles.modalBody]} maxFontSizeMultiplier={1.3}>
454	            {cascadeMessage(count)}
455	          </Text>
456	          <View style={styles.modalActions}>
457	            <View style={styles.modalActionItem}>
458	              <ButtonSecondary
459	                label="Cancel"
460	                onPress={onDismiss}
461	                disabled={saving}
462	                testID="edit-cascade-cancel"
463	              />
464	            </View>
465	            <View style={styles.modalActionItem}>
466	              <ButtonPrimary
467	                label="Continue"
468	                onPress={onConfirm}
469	                loading={saving}
470	                testID="edit-cascade-confirm"
471	              />
472	            </View>
473	          </View>
474	        </View>
475	      </View>
476	    </Modal>
477	  );
478	}
479	
480	function cascadeMessage(count: number | null): string {
481	  const n = count ?? 0;
482	  const noun = n === 1 ? 'pending application' : 'pending applications';
483	  return `This will cancel ${n} ${noun}. They'll be notified.`;
484	}
