1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  Pressable,
4	  RefreshControl,
5	  SafeAreaView,
6	  ScrollView,
7	  StyleSheet,
8	  Text,
9	  View,
10	} from 'react-native';
11	import { router } from 'expo-router';
12	import { CampaignCard, type CampaignCardCurrency } from '@/components/primitives/CampaignCard';
13	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
14	import { type StatusPillStatus } from '@/components/primitives/StatusPill';
15	import { Fab } from '@/components/shared/Fab';
