31	  title: string;
32	  listerHandle: string;
33	  priceCents: number;
34	  currency?: CampaignCardCurrency;
35	  preConditionSummary?: string;
36	  status?: StatusPillStatus;
37	  // Override for the pill's default text label — used when the upstream
38	  // enum doesn't map 1:1 to the StatusPill palette (e.g. listing_status
39	  // "active" rendered with the approved-green pill but labeled "Active"
40	  // rather than "Approved").
41	  statusLabel?: string;
