58	function formatPrice(priceCents: number, currency: CampaignCardCurrency): string {
59	  const whole = Math.round(priceCents / 100);
60	  // Fallback to the raw currency code when an unknown value sneaks in from
61	  // a callsite that cast an untyped string (e.g. RPC returns `text`): safer
62	  // than rendering "undefined5" if the DB ever holds a currency outside the
63	  // USD/EUR/GBP trio the wizard writes.
64	  const symbol = CURRENCY_SYMBOL[currency] ?? currency;
65	  return `${symbol}${whole.toLocaleString('en-US')}`;
66	}
67	
68	// Feed cell per docs/design.md §5.1 — hard-shadow card, 2px ink border. Press
69	// behavior per §1.4 line 103: shadow collapses (3,3) → (0,0) while the card
70	// translates (3,3) to mimic a physical press. Same animated-shadowOpacity + fixed
71	// shadowOffset pattern as Button/Chip since iOS shadowOffset is not animatable
72	// through Reanimated.
73	export function CampaignCard({
74	  title,
75	  listerHandle,
76	  priceCents,
77	  currency = 'USD',
78	  preConditionSummary,
79	  status,
80	  statusLabel,
81	  meta,
82	  onPress,
83	  style,
84	  testID,
85	}: CampaignCardProps) {
86	  const reduced = useReducedMotion();
87	  const pressed = useSharedValue(0);
88	  const interactive = !!onPress;
89	
90	  const animatedStyle = useAnimatedStyle(() => {
91	    const v = pressed.value;
92	    return {
93	      transform: [{ translateX: v * 3 }, { translateY: v * 3 }],
94	      shadowOpacity: 1 - v,
95	    };
96	  });
97	
98	  const handlePressIn = useCallback(() => {
99	    if (!interactive) return;
100	    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
101	    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
102	  }, [interactive, pressed, reduced]);
103	
104	  const handlePressOut = useCallback(() => {
105	    if (!interactive) return;
106	    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
107	  }, [interactive, pressed, reduced]);
108	
109	  return (
110	    <Pressable
111	      onPress={interactive ? onPress : undefined}
112	      onPressIn={handlePressIn}
113	      onPressOut={handlePressOut}
114	      disabled={!interactive}
115	      accessible={interactive}
116	      accessibilityRole={interactive ? 'button' : undefined}
117	      accessibilityLabel={interactive ? `${title} by ${listerHandle}` : undefined}
118	      testID={testID}
119	    >
120	      <Animated.View style={[styles.card, shadows.hard, animatedStyle, style]}>
121	        <Text style={[textStyles.h2, styles.title]} numberOfLines={2}>
122	          {title}
123	        </Text>
124	        <Text style={[textStyles.mono, styles.handle]} numberOfLines={1}>
125	          {listerHandle}
126	        </Text>
127	        {preConditionSummary ? (
128	          <Text style={[textStyles.caption, styles.preCondition]} numberOfLines={2}>
129	            {preConditionSummary}
130	          </Text>
131	        ) : null}
132	        <View style={styles.footerRow}>
133	          <Text style={[textStyles.h2, styles.price]}>{formatPrice(priceCents, currency)}</Text>
134	          {status ? <StatusPill status={status} label={statusLabel} /> : null}
135	        </View>
136	        {meta && meta.length > 0 ? (
137	          <Text
138	            style={[textStyles.caption, styles.meta]}
139	            numberOfLines={1}
140	            maxFontSizeMultiplier={1.3}
141	          >
142	            {meta.map((m) => `${m.value} ${m.label}`).join(' · ')}
143	          </Text>
144	        ) : null}
145	      </Animated.View>
146	    </Pressable>
147	  );
148	}
